for(let e of document.getElementsByClassName("date-format"))try{e.innerHTML=luxon.DateTime.fromISO(e.innerHTML).toFormat("fff")}catch(e){console.error(e)}for(let e of document.getElementsByClassName("markdown-format")){let t=new showdown.Converter;try{e.innerHTML=t.makeHtml(e.innerHTML)}catch(e){console.error(e)}}for(let e of document.getElementsByClassName("twemoji-format"))try{twemoji.parse(e)}catch(e){console.error(e)}function openNav(){document.getElementById("side-navigation").style.width="250px"}function closeNav(){document.getElementById("side-navigation").style.width="0"}function copyText(e){navigator.clipboard.writeText(e).then((function(){alert("Copied to clipboard!")}),(function(){alert("Failed to copy.")}))}document.onkeyup=function(e){"Escape"===e.key&&(document.body.innerHTML="",location.href="https://taiko.bui.pm/")};